package main

import (
	"bytes"
	"fmt"
	"html/template"
	"mime"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Validate and Sanitize Email Addresses
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// ParseAddress validates the format and ensures we work with a clean struct
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Prevent Header Injection (CRLF Injection)
	// We use MIME Q-encoding (Quoted-Printable) for the Subject.
	// This handles non-ASCII characters correctly and encodes control characters like \r\n,
	// preventing attackers from injecting malicious headers.
	fullSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", fullSubject)

	// Construct Headers
	// Note: We use from.String() and to.String() to use the sanitized versions of the addresses.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		from.String(),
		to.String(),
		encodedSubject,
	)

	// 3. Prevent HTML Injection (XSS)
	// Use html/template to safely construct the body. It automatically escapes
	// special characters in the input variables.
	const emailTpl = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.FeedbackContent}}</pre>
  </div>
</body>
</html>`

	// Create a data structure for the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Parse and Execute the template
	t, err := template.New("email").Parse(emailTpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Combine headers and safe HTML body
	emailMessage := headers + bodyBuffer.String()

	return emailMessage, nil
}

func main() {
	// Example usage
	body, err := BuildFeedbackEmail("user@example.com", "support@company.com", "John <script>alert(1)</script> Doe", "Login Issue", "I cannot login.\n<script>malicious code</script>")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println(body)
}

