package main

import (
	"fmt"
	"html"
	"log"
)

// BuildFeedbackEmail constructs an HTML email message suitable for sending via SMTP.
// It combines standard email headers with an HTML formatted body containing the user's feedback.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Sanitize inputs
	// We escape the input strings to ensure that special characters (like <, >, &)
	// are rendered as text and not interpreted as HTML tags. This prevents HTML injection.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// 2. Define Email Headers
	// The headers must be separated from the body by a blank line.
	// We use a map to organize headers, then serialize them.
	// Note: "Content-Type" is set to text/html with UTF-8 encoding.
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("User Feedback: %s", safeSubject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"UTF-8\""

	// 3. Construct Header String
	headerStr := ""
	for k, v := range headers {
		// SMTP headers must end with CRLF (\r\n)
		headerStr += fmt.Sprintf("%s: %s\r\n", k, v)
	}

	// 4. Define HTML Template
	// We use inline CSS to ensure the email looks good in most email clients.
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; color: #333333; line-height: 1.6; }
		.container { width: 100%%; max-width: 600px; margin: 0 auto; border: 1px solid #dddddd; border-radius: 5px; overflow: hidden; }
		.header { background-color: #0056b3; color: #ffffff; padding: 20px; text-align: center; }
		.content { padding: 20px; background-color: #f9f9f9; }
		.field-group { margin-bottom: 15px; }
		.label { font-weight: bold; color: #555555; display: block; margin-bottom: 5px; }
		.value { background-color: #ffffff; padding: 10px; border: 1px solid #e0e0e0; border-radius: 3px; }
		.message-box { white-space: pre-wrap; min-height: 100px; }
		.footer { background-color: #eeeeee; padding: 10px; text-align: center; font-size: 12px; color: #777777; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>New User Feedback</h2>
		</div>
		<div class="content">
			<div class="field-group">
				<span class="label">User Name:</span>
				<div class="value">%s</div>
			</div>
			<div class="field-group">
				<span class="label">Subject:</span>
				<div class="value">%s</div>
			</div>
			<div class="field-group">
				<span class="label">Feedback Content:</span>
				<div class="value message-box">%s</div>
			</div>
		</div>
		<div class="footer">
			<p>This is an automated message generated by the feedback system.</p>
		</div>
	</div>
</body>
</html>`

	// 5. Fill the template
	body := fmt.Sprintf(htmlTemplate, safeUserName, safeSubject, safeContent)

	// 6. Combine Headers and Body
	// The protocol requires a blank line (\r\n) between headers and the body.
	emailBody = headerStr + "\r\n" + body

	return emailBody, nil
}

func main() {
	// Simulation of input data
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe"
	subject := "Login Issue on Mobile"
	content := "Hello,\n\nI am unable to login to the mobile app when using 2FA. It works fine on desktop.\n\nPlease help."

	// Generate the email
	emailMsg, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		log.Fatalf("Failed to build email: %v", err)
	}

	// Output the result
	// In a real application, this string would be passed to net/smtp.SendMail as the 'msg' parameter.
	fmt.Println("--- Generated Email Message (Ready for SMTP) ---")
	fmt.Println(emailMsg)
	fmt.Println("------------------------------------------------")
}

