package main

import (
	"fmt"
	"html"
	"strings"
)

// BuildFeedbackEmail constructs a MIME-compliant HTML email message.
// It combines standard email headers with an HTML body containing the user's feedback.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Sanitize input for HTML inclusion to prevent XSS or HTML injection.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// 2. Convert newlines in the feedback content to HTML line breaks (<br>) for proper display.
	safeContent = strings.ReplaceAll(safeContent, "\n", "<br>")

	// 3. Construct the HTML body.
	// We use a simple inline style for better readability in email clients.
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { width: 100%%; max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
        .header { background-color: #f4f4f4; padding: 10px; border-bottom: 1px solid #ddd; margin-bottom: 20px; }
        .field { margin-bottom: 10px; }
        .label { font-weight: bold; color: #555; }
        .content-box { background-color: #f9f9f9; padding: 15px; border-left: 4px solid #007BFF; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback</h2>
        </div>
        <div class="field">
            <span class="label">User Name:</span> %s
        </div>
        <div class="field">
            <span class="label">Subject:</span> %s
        </div>
        <div class="field">
            <span class="label">Feedback Content:</span>
        </div>
        <div class="content-box">
            %s
        </div>
        <p style="font-size: 12px; color: #999; margin-top: 20px;">
            This email was auto-generated by the feedback system.
        </p>
    </div>
</body>
</html>`

	body := fmt.Sprintf(htmlTemplate, safeUserName, safeSubject, safeContent)

	// 4. Construct the MIME Headers.
	// Note: In a production environment, you might need to use MIME encoding (RFC 2047)
	// for the Subject line if it contains non-ASCII characters.
	headers := fmt.Sprintf("From: %s\r\n"+
		"To: %s\r\n"+
		"Subject: Feedback: %s\r\n"+
		"MIME-Version: 1.0\r\n"+
		"Content-Type: text/html; charset=\"UTF-8\"\r\n"+
		"\r\n", // The double CRLF (\r\n\r\n) separates headers from the body
		fromAddr, toAddr, subject)

	// 5. Combine headers and body
	emailBody = headers + body

	return emailBody, nil
}

func main() {
	// Sample data
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe"
	subject := "Login Issue"
