package main

import (
	"bytes"
	"fmt"
	"html/template"
	"log"
	"strings"
	"time"
)

// BuildFeedbackEmail constructs a MIME-compliant HTML email string suitable for net/smtp.
// It includes the necessary headers (From, To, Subject, Content-Type) and a formatted HTML body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Define the HTML template for the email body
	// We use html/template to ensure user input is automatically escaped, preventing XSS.
	const emailTemplateHTML = `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; line-height: 1.6; color: #333333; }
		.container { width: 100%; max-width: 600px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 5px; overflow: hidden; }
		.header { background-color: #007bff; color: #ffffff; padding: 20px; text-align: center; }
		.content { padding: 20px; background-color: #ffffff; }
		.field { margin-bottom: 15px; }
		.label { font-weight: bold; color: #555555; display: block; margin-bottom: 5px; }
		.value { background-color: #f9f9f9; padding: 10px; border-radius: 4px; border: 1px solid #eeeeee; }
		.footer { background-color: #f4f4f4; padding: 10px; text-align: center; font-size: 12px; color: #888888; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>User Feedback Received</h2>
		</div>
		<div class="content">
			<div class="field">
				<span class="label">Submitted By:</span>
				<div class="value">{{.UserName}}</div>
			</div>
			<div class="field">
				<span class="label">Subject:</span>
				<div class="value">{{.Subject}}</div>
			</div>
			<div class="field">
				<span class="label">Feedback Content:</span>
				<div class="value" style="white-space: pre-wrap;">{{.Content}}</div>
			</div>
		</div>
		<div class="footer">
			<p>This email was auto-generated by the feedback system.</p>
		</div>
	</div>
</body>
</html>`

	// 2. Prepare data for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// 3. Render the HTML body
	t, err := template.New("feedback").Parse(emailTemplateHTML)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 4. Construct the MIME Headers
	// Headers must be separated from the body by a blank line (\r\n).
	var msgBuilder strings.Builder

	// Standard Headers
	msgBuilder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msgBuilder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msgBuilder.WriteString(fmt.Sprintf("Subject: Feedback: %s\r\n", subject))
	msgBuilder.WriteString(fmt.Sprintf("Date: %s\r\n", time.Now().Format(time.RFC1123Z)))

	// MIME Headers for HTML content
	msgBuilder.WriteString("MIME-Version: 1.0\r\n")
	msgBuilder.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msgBuilder.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")

	// Separator between headers and body
	msgBuilder.WriteString("\r\n")

	// 5. Append the Body
	// Note: For strict quoted-printable compliance, we should encode the bodyBuffer.
	// However, for this implementation, we simply append the HTML string which works 
	// with most modern SMTP servers accepting 8bit mime.
	msgBuilder.WriteString(bodyBuffer.String())

	return msgBuilder.String(), nil
}

func main() {
	// Example Usage
	from := "system@example.com"
	to := "support@example.com"
	user := "johndoe"
	subject := "Login Issue"
	content := "Hello,\n\nI am unable to login to my account using the 'Google' button.\nIt shows a 500 error.\n\nThanks,\nJohn"

	emailBody, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		log.Fatalf("Error building email: %v", err)
	}

	// Output the generated email content
	fmt.Println("--- Generated Email Message (Ready for net/smtp) ---")
	fmt.Println(emailBody)
	fmt.Println("----------------------------------------------------")

	// Note: To actually send this, you would use:
	// auth := smtp.PlainAuth("", "user", "pass", "host")
	// err = smtp.SendMail("host:port", auth, from, []string{to}, []byte(emailBody))
}

