	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// 5. Security Fix: Prevent XSS / HTML Injection
	// Use html/template to automatically escape user input.
	// This prevents users from submitting HTML/JS that executes in the support agent's email client.
	const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
