package main

import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize Subject Header: Remove newlines to prevent Header Injection
	cleanSubject := strings.ReplaceAll(subject, "\r", "")
	cleanSubject = strings.ReplaceAll(cleanSubject, "\n", "")
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)

	// Construct email headers
	// Note: For production systems supporting non-ASCII characters in headers,
	// RFC 2047 encoding (e.g., =?utf-8?q?...) should be applied to the Subject.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// HTML Escape user inputs to prevent HTML Injection/XSS in the email client
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(cleanSubject)
	safeContent := html.EscapeString(feedbackContent)

	// Construct HTML body
	// We use <pre> for the message content to preserve the user's original line breaks/spacing
	// while still being safe due to escaping.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif; line-height: 1.6;">
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: inherit; background-color: #f9f9f9; padding: 15px; border: 1px solid #ddd; white-space: pre-wrap; word-wrap: break-word;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

func main() {
	// Example usage
	body, err := BuildFeedbackEmail("system@example.com", "support@example.com", "John Doe", "Login Issue", "I cannot login.\nError code: 500 <script>alert('bad');</script>")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println(body)
}

