// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Validate email addresses
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Security Fix: Prevent Header Injection (CRLF Injection)
	// The subject must not contain newlines, otherwise an attacker could inject
	// arbitrary headers or terminate the headers section prematurely.
	if strings.ContainsAny(subject, "\r\n") {
		return "", errors.New("subject contains invalid characters (newlines)")
	}

	// 3. Security Fix: Prevent HTML Injection (XSS)
	// Use html/template to safely escape user input.
	// fmt.Sprintf is unsafe for HTML generation because it does not escape special characters.
	const htmlTpl = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.Content}}</pre>
  </div>
</body>
</html>`

	// Parse the template
	t, err := template.New("email").Parse(htmlTpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare data for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Execute template into a buffer
	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 4. Construct Headers
	// Note: For a robust production system, non-ASCII subjects should be MIME-encoded (RFC 2047).
	// Here we ensure the basic structure is safe.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: Feedback: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		subject,
	)

	// Combine headers and the safely escaped HTML body
	emailMessage := headers + bodyBuffer.String()

	return emailMessage, nil
