// BuildFeedbackEmail constructs a MIME-compliant HTML email message suitable for sending via net/smtp.
// It includes the necessary headers and a formatted HTML body containing the user's feedback.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Define the HTML template structure.
	// We use inline CSS to ensure maximum compatibility with email clients.
	const htmlTemplateStr = `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; color: #333333; line-height: 1.6; }
		.container { width: 100%; max-width: 600px; margin: 0 auto; border: 1px solid #dddddd; padding: 20px; background-color: #ffffff; }
		.header { border-bottom: 2px solid #007bff; padding-bottom: 10px; margin-bottom: 20px; }
		.header h2 { margin: 0; color: #007bff; }
		.field-group { margin-bottom: 15px; }
		.label { font-weight: bold; display: block; margin-bottom: 5px; color: #555555; }
		.value { background-color: #f9f9f9; padding: 10px; border-radius: 4px; border: 1px solid #eeeeee; white-space: pre-wrap; }
		.footer { margin-top: 30px; font-size: 12px; color: #888888; text-align: center; border-top: 1px solid #eeeeee; padding-top: 10px; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>New User Feedback</h2>
		</div>

		<div class="field-group">
			<span class="label">User Name:</span>
			<div class="value">{{.UserName}}</div>
		</div>

		<div class="field-group">
			<span class="label">Subject:</span>
			<div class="value">{{.Subject}}</div>
		</div>

		<div class="field-group">
			<span class="label">Feedback Content:</span>
			<div class="value">{{.Content}}</div>
		</div>

		<div class="footer">
			<p>This email was automatically generated by the User Feedback System.</p>
		</div>
	</div>
</body>
</html>`

	// 2. Prepare the data object for the template.
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// 3. Parse and execute the template.
	// Using html/template handles escaping automatically, preventing HTML injection attacks.
	tmpl, err := template.New("feedback_email").Parse(htmlTemplateStr)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := tmpl.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 4. Construct the MIME Headers.
	// The Subject header in the email envelope is usually distinct from the content subject.
	// We format it to make it easy for support staff to filter.
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Note: For production systems, headers containing non-ASCII characters should be 
	// encoded using RFC 2047 (e.g., =?utf-8?B?...?=). For this implementation, we assume UTF-8 text.
	headers := []string{
		fmt.Sprintf("From: %s", fromAddr),
		fmt.Sprintf("To: %s", toAddr),
		fmt.Sprintf("Subject: %s", emailSubject),
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=\"UTF-8\"",
	}

	// 5. Assemble the final message.
	// SMTP requires headers to be separated by CRLF (\r\n) and a blank line between headers and body.
	headerStr := strings.Join(headers, "\r\n")
	emailBody = headerStr + "\r\n\r\n" + bodyBuffer.String()

	return emailBody, nil
}

func main() {
	// Simulation inputs
	from := "no-reply@example.com"
	to := "support@example.com"
	user := "Alice Smith"
	subject := "Login Button Issue"
	content := "Hi Team,\n\nI noticed that the login button is misaligned on the mobile view.\nPlease fix it.\n\nThanks!"

	// Generate the email
	emailPayload, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	// Output the result
	fmt.Println("--- Generated Email Payload (ready for net/smtp) ---")
	fmt.Println(emailPayload)
	fmt.Println("----------------------------------------------------")

	/* 
