// BuildFeedbackEmail constructs a MIME-formatted HTML email string.
// It escapes user input to prevent HTML injection and formats the feedback nicely.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic Validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr are required")
	}

	// 2. Sanitize User Input
	// It is crucial to escape user input to prevent HTML injection/XSS when viewed in webmail clients.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// Preserve line breaks from the text area by converting \n to <br>
	safeContent = strings.ReplaceAll(safeContent, "\n", "<br>")

	// 3. Define Email Headers
	// We use a specific order for headers which is standard practice.
	// Note: For a production system supporting international characters in Headers (e.g., Subject),
	// one should use mime.QEncoding.Encode(). For this example, we assume UTF-8 support.
	var headers strings.Builder
	headers.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	headers.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	headers.WriteString(fmt.Sprintf("Subject: User Feedback: %s\r\n", subject)) // Raw subject in header usually needs MIME encoding if non-ASCII
	headers.WriteString("MIME-Version: 1.0\r\n")
	headers.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")

	// 4. Define HTML Body Template
	// We use simple inline CSS to ensure compatibility with most email clients.
	htmlTemplate := `
<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; color: #333333; line-height: 1.6; }
		.container { width: 100%%; max-width: 600px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 5px; overflow: hidden; }
		.header { background-color: #0056b3; color: #ffffff; padding: 20px; text-align: center; }
		.content { padding: 20px; background-color: #ffffff; }
		.field { margin-bottom: 15px; }
		.label { font-weight: bold; color: #555555; display: block; margin-bottom: 5px; }
		.value { background-color: #f9f9f9; padding: 10px; border-radius: 4px; border: 1px solid #eee; }
		.footer { background-color: #f4f4f4; padding: 10px; text-align: center; font-size: 12px; color: #888888; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>New User Feedback</h2>
		</div>
		<div class="content">
			<div class="field">
				<span class="label">User Name:</span>
				<div class="value">%s</div>
			</div>
			<div class="field">
				<span class="label">Subject:</span>
				<div class="value">%s</div>
			</div>
			<div class="field">
				<span class="label">Feedback Content:</span>
				<div class="value">%s</div>
			</div>
		</div>
		<div class="footer">
			<p>This email was automatically generated by the User Feedback System.</p>
		</div>
	</div>
</body>
</html>`

	// Fill the template with sanitized data
	bodyContent := fmt.Sprintf(htmlTemplate, safeUserName, safeSubject, safeContent)

	// 5. Combine Headers and Body
	// SMTP requires a blank line (\r\n) between headers and body.
	fullMessage := headers.String() + "\r\n" + bodyContent

	return fullMessage, nil
}

func main() {
	// Example Usage
	from := "system@example.com"
	to := "support@yourcompany.com"
	user := "Alice Smith"
	subj := "Login Button Issue"
	content := "Hello,\n\nI noticed that the login button is not responsive on the mobile version of the site.\nPlease investigate.\n\nThanks!"

	emailMsg, err := BuildFeedbackEmail(from, to, user, subj, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	// Print the result to stdout to demonstrate the output format
	fmt.Println("----- Generated Email Message (Ready for net/smtp) -----")
	fmt.Println(emailMsg)
	fmt.Println("--------------------------------------------------------")

	// Note: To actually send this, you would use:
	// smtp.SendMail("smtp.example.com:587", auth, from, []string{to}, []byte(emailMsg))
}

