	// 4. Construct email headers
	// We use a standard MIME structure.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// 5. Sanitize inputs for HTML Body (XSS Protection)
	// We must escape special HTML characters to prevent HTML injection.
	safeUserName := html.EscapeString(userName)
	safeSubjectBody := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// 6. Construct HTML body
	// Added 'white-space: pre-wrap' to the pre tag so text wraps on mobile devices
	// while preserving user formatting.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
