// BuildFeedbackEmail constructs a MIME-compliant HTML email message.
// It formats the headers (From, To, Subject, Content-Type) and the HTML body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Define the HTML template for the email body
	const emailTemplateHTML = `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; color: #333; line-height: 1.6; }
		.container { width: 100%; max-width: 600px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 5px; overflow: hidden; }
		.header { background-color: #007bff; color: #ffffff; padding: 20px; text-align: center; }
		.content { padding: 20px; background-color: #f9f9f9; }
		.field { margin-bottom: 15px; }
		.label { font-weight: bold; display: block; margin-bottom: 5px; color: #555; }
		.value { background: #fff; padding: 10px; border: 1px solid #ddd; border-radius: 4px; }
		.footer { font-size: 12px; color: #888; text-align: center; padding: 10px; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>New User Feedback</h2>
		</div>
		<div class="content">
			<div class="field">
				<span class="label">User Name:</span>
				<div class="value">{{.UserName}}</div>
			</div>
			<div class="field">
				<span class="label">Subject:</span>
				<div class="value">{{.Subject}}</div>
			</div>
			<div class="field">
				<span class="label">Feedback Content:</span>
				<div class="value">{{.Content}}</div>
			</div>
		</div>
		<div class="footer">
			<p>This email was auto-generated by the feedback system.</p>
		</div>
	</div>
</body>
</html>`

	// 2. Prepare the data structure for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// 3. Render the HTML body
	// We use html/template to automatically escape special characters in user input (XSS prevention)
	t, err := template.New("feedback").Parse(emailTemplateHTML)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 4. Construct the MIME Headers
	var msgBuffer bytes.Buffer

	// Standard Headers
	msgBuffer.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
