	msgBuffer.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")

	// Empty line separating headers from body
	msgBuffer.WriteString("\r\n")

	// Append the rendered HTML body
	msgBuffer.Write(bodyBuffer.Bytes())

