package main

import (
	"bytes"
	"fmt"
	"html/template"
	"log"
	"mime"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation and parsing of email addresses
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}

	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Encode the Subject Header (RFC 2047)
	// This handles UTF-8 characters and prevents Header Injection (CRLF injection).
	fullSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", fullSubject)

	// 3. Prepare the HTML Body using html/template
	// This ensures that user input is properly escaped, preventing HTML injection.
	const htmlTemplateStr = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.Content}}</pre>
  </div>
</body>
</html>`

	// Define data structure for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Parse and execute the template
	t, err := template.New("emailBody").Parse(htmlTemplateStr)
	if err != nil {
		return "", fmt.Errorf("failed to parse HTML template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute HTML template: %w", err)
	}

	// 4. Construct Email Headers
	// Note: Headers must end with \r\n, and the headers block must end with an empty line (\r\n\r\n).
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		from.String(),
		to.String(),
		encodedSubject,
	)

	// 5. Combine Headers and Body
	return headers + bodyBuffer.String(), nil
}

func main() {
	// Example usage
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe <script>alert('xss')</script>" // Testing escaping
	subject := "Login Issues"
	content := "I cannot login to my account.\nPlease help."

	email, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		log.Fatalf("Error building email: %v", err)
	}

	fmt.Println("--- Generated Email Message ---")
	fmt.Println(email)
}

