func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Define the HTML template
	const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
		.container { width: 80%; margin: 20px auto; border: 1px solid #ddd; padding: 20px; border-radius: 5px; background-color: #f9f9f9; }
		.header { background-color: #007bff; color: #ffffff; padding: 10px; border-radius: 5px 5px 0 0; }
