		.label { font-weight: bold; color: #555; }
		.content { background-color: #fff; padding: 15px; border: 1px solid #eee; border-radius: 3px; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>User Feedback Received</h2>
		</div>
		<div class="field">
			<span class="label">Submitted By:</span> {{.UserName}}
		</div>
		<div class="field">
			<span class="label">Subject:</span> {{.Subject}}
		</div>
		<div class="field">
			<div class="label">Feedback Content:</div>
			<div class="content">
				{{.FeedbackContent}}
			</div>
		</div>
		<p style="font-size: 0.8em; color: #777;">This email was automatically generated by the feedback system.</p>
	</div>
</body>
</html>`

	// 2. Prepare the data
	data := FeedbackData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// 3. Execute the template
	// We use html/template to ensure special characters in user input are escaped properly (XSS prevention)
	t, err := template.New("feedback").Parse(htmlTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 4. Construct the MIME Headers
	// SMTP headers must be separated by \r\n
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = "New Feedback: " + subject
