package main

import (
	"errors"
	"fmt"
	"html"
	"strings"
)

// BuildFeedbackEmail constructs a MIME-compliant HTML email string suitable for sending via net/smtp.
// It escapes user input to prevent HTML injection/XSS when viewed by support staff.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", errors.New("fromAddr and toAddr cannot be empty")
	}

	// 1. Sanitize user inputs to prevent HTML injection (XSS) in the email body
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// Convert newlines in feedback content to HTML line breaks for readability
	safeContentHtml := strings.ReplaceAll(safeContent, "\n", "<br>")

	// 2. Construct the HTML Body
	// We use a simple, clean HTML structure.
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
		.container { width: 100%%; max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
		.header { background-color: #f4f4f4; padding: 10px; border-bottom: 1px solid #ddd; }
		.field { margin-bottom: 10px; }
		.label { font-weight: bold; color: #555; }
		.content { margin-top: 20px; padding: 15px; background-color: #f9f9f9; border-left: 4px solid #007BFF; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>User Feedback Report</h2>
		</div>
		<div class="field">
			<span class="label">Submitted By:</span> %s
		</div>
		<div class="field">
			<span class="label">Subject:</span> %s
		</div>
		<div class="field">
			<span class="label">Feedback Content:</span>
			<div class="content">
				%s
			</div>
		</div>
		<p style="font-size: 0.8em; color: #888;">This email was auto-generated by the feedback system.</p>
	</div>
</body>
</html>`

	body := fmt.Sprintf(htmlTemplate, safeUserName, safeSubject, safeContentHtml)

	// 3. Construct SMTP Headers
	// Note: Headers must be separated from the body by a blank line (\r\n).
	// We use strings.Builder for efficient concatenation.
	var msgBuilder strings.Builder

	// Standard Headers
	msgBuilder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msgBuilder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msgBuilder.WriteString(fmt.Sprintf("Subject: Feedback: %s\r\n", subject)) // Using original subject in header

	// MIME Headers for HTML Email
	msgBuilder.WriteString("MIME-Version: 1.0\r\n")
	msgBuilder.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msgBuilder.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")

	// End of headers
	msgBuilder.WriteString("\r\n")

	// 4. Combine Headers and Body
	// For a production system, you might want to implement a Quoted-Printable encoder here
	// to ensure line lengths don't exceed SMTP limits (76 chars).
	// For this example, we append the body directly.
	msgBuilder.WriteString(body)

	return msgBuilder.String(), nil
}

func main() {
	// Example Usage
	from := "system@example.com"
	to := "support@example.com"
	user := "John Doe"
	subject := "Login Issue"
	content := "Hello,\n\nI am unable to login to my account. It says 'Invalid Password' even though I just reset it.\n\nThanks,\nJohn"

	emailPayload, err := BuildFeedbackEmail(from, to, user, subject, content)
