)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// 2. Validate email addresses format
	// This helps prevent basic injection in the address fields, though SMTP servers handle this too.
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 3. Construct Email Headers securely
	// FIX: Use MIME encoding for the Subject header.
	// This prevents Email Header Injection (CRLF injection) by encoding newlines and special characters.
	// It also handles non-ASCII characters correctly (RFC 2047).
	fullSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", fullSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// 4. Construct HTML body securely
	// FIX: Use html/template to prevent HTML Injection/XSS.
	// fmt.Sprintf is unsafe for HTML generation with user input.
	const emailTemplateHTML = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.Content}}</pre>
  </div>
</body>
</html>`

	// Parse the template
	t, err := template.New("feedback").Parse(emailTemplateHTML)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Create a buffer to store the rendered HTML
	var bodyBuffer bytes.Buffer
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Execute the template. This automatically escapes special HTML characters.
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 5. Combine headers and body
	emailMessage := headers + bodyBuffer.String()

	return emailMessage, nil
}

func main() {
	// Example usage
