package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate and parse email addresses
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct email headers
	// 1. Encode the subject using MIME Q-encoding (RFC 2047).
	// This handles UTF-8 characters and prevents Header Injection attacks (newlines in subject).
	fullSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", fullSubject)

	// 2. Build the headers block.
	// We use the parsed address strings to ensure standard compliance.
	headers := fmt.Sprintf("From: %s\r\n", from.String())
	headers += fmt.Sprintf("To: %s\r\n", to.String())
	headers += fmt.Sprintf("Subject: %s\r\n", encodedSubject)
	headers += "MIME-Version: 1.0\r\n"
	headers += "Content-Type: text/html; charset=UTF-8\r\n"
	headers += "\r\n" // Double CRLF marks the end of headers and start of body

	// Construct HTML body
	// 3. Sanitize user input to prevent HTML Injection.
	// We must escape special characters (<, >, &, ", ') so they render as text, not HTML tags.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

func main() {
	// Example usage
	body, err := BuildFeedbackEmail(
		"system@example.com",
		"support@example.com",
		"John <Doe>",
		"Login Issues & Bug Report",
		"Hello,\nI cannot login properly. It says \"Error 500\".\n<script>alert('test')</script>",
	)

	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println(body)
}

