	}

	// 1. Sanitize Subject for Headers (Prevent Header Injection)
	// Newlines in headers allow attackers to inject arbitrary headers (e.g., Bcc).
	safeSubjectHeader := strings.ReplaceAll(subject, "\r", "")
	safeSubjectHeader = strings.ReplaceAll(safeSubjectHeader, "\n", "")
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubjectHeader)

	// 2. Construct HTML Body using html/template (Prevent HTML Injection)
	// We use text/template or html/template to automatically escape user input
	// so that characters like '<' or '>' do not break the HTML structure.
	const htmlTpl = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.Content}}</pre>
  </div>
</body>
</html>`

	// Prepare data for the template
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject, // We can use the original subject in the body, the template will escape it
		Content:  feedbackContent,
	}

	// Parse and execute the template
	t, err := template.New("email").Parse(htmlTpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// 3. Construct Headers
	// Headers must be separated from the body by a blank line (\r\n\r\n)
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Combine headers and body
	emailMessage := headers + bodyBuffer.String()

	return emailMessage, nil
}

