package main

import (
	"fmt"
	"html"
	"log"
	"strings"
)

// BuildFeedbackEmail constructs an HTML formatted email string suitable for sending via SMTP.
// It includes necessary headers (From, To, Subject, MIME-Version, Content-Type) and an HTML body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Sanitize user input to prevent HTML injection (XSS) when viewed by support staff.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// Convert newlines in the feedback content to HTML line breaks for better readability.
	formattedContent := strings.ReplaceAll(safeContent, "\n", "<br>")

	// 2. Construct the HTML Body.
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<style>
		body { font-family: Arial, sans-serif; color: #333; line-height: 1.6; }
		.container { border: 1px solid #ddd; padding: 20px; max-width: 600px; margin: 0 auto; }
		.header { background-color: #f8f9fa; padding: 10px; border-bottom: 1px solid #eee; margin-bottom: 20px; }
		.label { font-weight: bold; color: #555; }
		.content-box { background-color: #fcfcfc; border: 1px solid #eee; padding: 15px; margin-top: 5px; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h2>User Feedback Received</h2>
		</div>
		<p><span class="label">Submitted By:</span> %s</p>
		<p><span class="label">Subject:</span> %s</p>
		<div class="label">Feedback Content:</div>
		<div class="content-box">
			%s
		</div>
		<p style="font-size: 0.8em; color: #888;">This email was auto-generated by the feedback system.</p>
	</div>
</body>
</html>`

	body := fmt.Sprintf(htmlTemplate, safeUserName, safeSubject, formattedContent)

	// 3. Construct Email Headers.
	// Note: Headers must be separated by CRLF (\r\n).
	// The body is separated from headers by a blank line (double CRLF).
	var msgBuilder strings.Builder

	msgBuilder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msgBuilder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msgBuilder.WriteString(fmt.Sprintf("Subject: Feedback: %s\r\n", subject))
	msgBuilder.WriteString("MIME-Version: 1.0\r\n")
	msgBuilder.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msgBuilder.WriteString("\r\n") // Blank line between headers and body
	msgBuilder.WriteString(body)

	return msgBuilder.String(), nil
}

func main() {
	// Example usage
	from := "system@example.com"
	to := "support@example.com"
	user := "johndoe"
	subj := "Login Button Issue"
