package main

import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// 2. Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 3. Security: Sanitize inputs for HTML Body
	// We must escape special characters (like <, >, &) to prevent HTML injection (XSS)
	// if the user submits malicious code in the feedback.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// 4. Security: Sanitize Subject for Email Headers
	// Remove newlines to prevent Email Header Injection.
	headerSubjectRaw := fmt.Sprintf("Feedback: %s", subject)
	headerSubject := strings.ReplaceAll(headerSubjectRaw, "\r", "")
	headerSubject = strings.ReplaceAll(headerSubject, "\n", "")

	// 5. Construct email headers
	// Note: For a robust system handling non-ASCII characters in headers,
	// MIME encoding (RFC 2047) should be used for the Subject line.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		headerSubject,
	)

	// 6. Construct HTML body
	// We use the 'safe' variables here.
	// white-space: pre-wrap is added to the <pre> tag to ensure long lines wrap correctly.
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`

	htmlBody := fmt.Sprintf(htmlTemplate,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// 7. Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

func main() {
	// Example usage
	body, err := BuildFeedbackEmail("system@example.com", "support@example.com", "John Doe", "Login Issue", "I cannot login with my <b>password</b>.")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println(body)
}

